import{_ as s,C as t,o as h,c,j as a,a as i,E as n,a3 as m}from"./chunks/framework.CVjg771q.js";const P=JSON.parse('{"title":"帛书第3章 闻道","description":"帛书德篇第3章 · 闻道（通行本第41章）","frontmatter":{"title":"帛书第3章 闻道","description":"帛书德篇第3章 · 闻道（通行本第41章）","category":"guide","aliases":["帛书第3章","马王堆老子3","通行本第41章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/texts/dao-de-jing-boshu/chapter-03.md","filePath":"daoism/texts/dao-de-jing-boshu/chapter-03.md","lastUpdated":1778755688000}'),u={name:"daoism/texts/dao-de-jing-boshu/chapter-03.md"};function p(x,e,g,b,_,f){const o=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),d=t("DaoLineGuide"),l=t("DaoKeywordCards");return h(),c("div",null,[e[0]||(e[0]=a("h1",{id:"帛书老子第3章",tabindex:"-1"},[i("帛书老子第3章 "),a("a",{class:"header-anchor",href:"#帛书老子第3章","aria-label":'Permalink to "帛书老子第3章"'},"​")],-1)),n(o,{title:"第3章 闻道",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第41章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第3章"},{label:"对照",text:"通行本第41章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(r,{paragraphs:["上士闻道 堇而行之","中士闻道 若存若亡","下士闻道 大笑之","弗笑 不足以为道","是以建言有之曰","明道如费 进道如退","夷道如颣 上德如浴","大白如辱 广德如不足","建德如偷 质真如渝","大方无隅 大器免成","大音希声 天象无形","道殷无名","夫唯道 善始且善成"]}),n(d,{lines:[{text:"上士闻道 堇而行之",tone:"起",guide:"上等根器的人听到道，勤勉地践行——帛书「堇」通「勤」，不是听闻就算了，而是立即行动。"},{text:"中士闻道 若存若亡",tone:"承",guide:"中等根器的人听到道，半信半疑——有时觉得在，有时觉得不在，不能坚定。"},{text:"下士闻道 大笑之",tone:"承",guide:"下等根器的人听到道，哈哈大笑——因为道说的和他们习以为常的认知正好相反。"},{text:"弗笑 不足以为道",tone:"转",guide:"如果不被嘲笑，那就不足以称为道了——道与世俗之见的距离，恰恰是衡量道的标尺。"},{text:"是以建言有之曰",tone:"引",guide:"所以古语有这样的说法——以下引用的「建言」是古已有之的格言。"},{text:"明道如费 进道如退",tone:"反",guide:"光明的道好像暗昧（费通昧），前进的道好像在后退——道的表象和实质往往相反。"},{text:"夷道如颣 上德如浴",tone:"反",guide:"平坦的道好像崎岖（颣即不平），最高的德好像低谷（浴通谷）——真正的平坦不显平坦，真正的崇高甘居低下。"},{text:"大白如辱 广德如不足",tone:"反",guide:"最洁白的好像有污点（辱），最广大的德好像不够——极致往往以相反的面貌出现。"},{text:"建德如偷 质真如渝",tone:"反",guide:"刚健的德好像怠惰（偷），纯真的质好像会变（渝）——帛书此句揭示了「正言若反」的思维模式。"},{text:"大方无隅 大器免成",tone:"断",guide:"最大的方形没有棱角，最大的器物不需刻意完成——帛书「大器免成」对比通行本「大器晚成」，义理差异极大：「免成」是不刻意求成，更合老子无为之意。"},{text:"大音希声 天象无形",tone:"断",guide:"最大的声音反而听不见，天象没有固定的形状——凡是可以被感知到的，就已经不是最大、最根本的了。"},{text:"道殷无名",tone:"断",guide:"道盛大（殷）却没有名称——越是根本的东西，越无法被命名。帛书「道殷无名」通行本作「道隐无名」。"},{text:"夫唯道 善始且善成",tone:"收",guide:"只有道，既善于开始，也善于完成——善始不易，善成更难，道贯穿始终。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(l,{items:[{term:"堇",pinyin:["jǐn"],meaning:"通「勤」——勤勉、勤劳。堇而行之即勤勉践行。",context:"帛书用此古字，通行本作「勤」。"},{term:"费",pinyin:["fèi"],meaning:"通「昧」——暗昧不明。明道如费：光明的道看起来反而暗昧。",context:"帛书作费，通行本校读为昧。"},{term:"颣",pinyin:["lèi"],meaning:"丝上的疙瘩，引申为不平、崎岖。夷道如颣：平坦的道看起来像崎岖不平。",context:"帛书用此古字，通行本作「纇」。"},{term:"浴",pinyin:["yù"],meaning:"通「谷」——山谷、低谷。上德如浴：最高的德像低谷一样谦下。",context:"帛书常以「浴」为「谷」。"},{term:"辱",pinyin:["rǔ"],meaning:"此处指污浊、有污点。大白如辱：最洁白的东西看起来好像有污点。",context:"与通行本同，白与辱的对照贯穿道家「反向思维」。"},{term:"偷",pinyin:["tōu"],meaning:"怠惰、苟且。建德如偷：刚健的德看起来好像怠惰——不是真的怠惰，而是不刻意表现。",context:"帛书「建德如偷」揭示德之刚健不在于外在表现。"},{term:"渝",pinyin:["yú"],meaning:"改变、变化。质真如渝：纯真的质看起来好像会变化。",context:"至真不显其真，正如至白若辱。"},{term:"免成",pinyin:["miǎn","chéng"],meaning:"不刻意求成。大器免成：最大的器物不需刻意完成——帛书此与通行本「大器晚成」义异，更合老子无为思想。",context:"帛书此条文献价值极高，是考辨《老子》版本的关键异文。"},{term:"殷",pinyin:["yīn"],meaning:"盛大、众多。道殷无名：道虽然盛大却没有名称。",context:"帛书作殷，通行本或作「隐」，义理侧重不同：殷强调道的充盈盛大。"}]}),e[3]||(e[3]=m('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>本章标题为「闻道」，帛书此章围绕「上士中士下士闻道」展开。帛书甲本以古字「亓」「恒」「邦」「靓」等呈现了比通行本更早的文本面貌，读者在阅读时需要注意这些古字的含义及与通行本的对应关系。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>本章在帛书《老子》中的重要性体现在：其一，文本上保留了战国至汉初的古字写法，是考证《老子》流传演变的重要实物；其二，义理上与通行本基本一致但用字更古，某些关键概念（如恒vs常、邦vs国）的差异反映了思想史的重要变化；其三，作为现存最早的《老子》完整写本之一，每章都是理解老子原始思想的珍贵窗口。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>今天读这一章，建议分两步。第一步，先顺读原文，感受帛书古朴的文字气息。第二步，对照通行本对应章节（括号中标注），体会异文带来的理解差异。帛书本提醒我们：经典文本从来不是凝固不变的——每一次抄写，都可能是一次微小的诠释。这种对文本流动性的感知，本身就是一种珍贵的学习体验。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>马王堆汉墓帛书《老子》甲本（底本）</li><li>对应通行本第41章，所属帛书德篇</li><li>高明《帛书老子校注》</li><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li></ul>',13))])}const q=s(u,[["render",p]]);export{P as __pageData,q as default};
